#include<bits/stdc++.h>
using namespace std;
int n,x[100010],y[100010];
int solve(int a[],int b[])
{
    int l1=1,r1=n,l2=1,r2=n;
    int ans=0;
    while(l1<=r1&&l2<=r2)
    {
        if(a[l1]>b[l2])
        {
            ans+=2;
            l1++;
            l2++;
        }
        else if(a[r1]>b[r2])
        {
            ans+=2;
            r1--;
            r2--;
        }
        else
        {
            ans+=(a[l1]==b[r2]);
            l1++;
            r2--;
        }
    }
    return ans;
}
int main()
{
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&x[i]);
    }
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&y[i]);
    }
    sort(x+1,x+1+n);
    sort(y+1,y+1+n);
    printf("%d %d",solve(x,y),n*2-solve(y,x));
    return 0;
}
